+
+    // Add Bayes factors if galaxy_brain mode or requested
+    if args.galaxy_brain || args.include.contains(&"bayes_factors".to_string()) {
+        let bf_entries: Vec<serde_json::Value> = ledger
+            .bayes_factors
+            .iter()
+            .map(|bf| {
